INSERT INTO public.meme_templates (name,description,image_url,text_box_count,example_texts,tags,popularity_score,embedding,created_at) VALUES
	 ('Inhaling-Seagull','This meme template features a series of four vertically stacked images depicting a seagull, capturing its progression from a calm state to an intense, dramatic reaction.

In the first panel, we see a seagull perched on what appears to be a green-painted wooden ledge. The bird is white with a yellow beak and is facing to the right, looking calm and composed. The background suggests an urban or built environment, with some wooden structures visible.

The second panel shows the same seagull, but now its posture has changed slightly. Its head is raised a bit higher, and its beak is open slightly, as if it''s about to vocalize or react to something.

In the third panel, we see a dramatic shift. The seagull''s neck is extended, its beak is wide open, and it appears to be squawking or screeching intensely. The bird''s body language conveys a sudden, strong reaction to something unseen.

The fourth and final panel is a stark contrast to the others. It''s bathed in a deep red color, creating a sense of alarm or intensity. The seagull is barely visible, appearing as a blurred white shape against the red background. This panel suggests motion and chaos, as if the bird has suddenly taken flight in a frenzy or is flailing about dramatically.

This meme template is often used to portray a situation where someone or something starts off calm but progressively becomes more agitated or reactive, culminating in an over-the-top, possibly irrational response. The stark transition from the detailed, realistic images to the abstract red panel emphasizes the extreme nature of the final reaction, making it a versatile template for depicting overreactions or escalating situations in a humorous way.','/memes/Inhaling-Seagull.jpg',2,'{}','{"inhaling bird"}',0.0,'[-0.007162778,0.001422893,0.015282116,0.020268697,0.013838444,-0.07603207,-0.02405037,0.014306395,0.008644859,0.03410176,-9.316714e-05,0.0022742162,0.023776269,0.018349357,0.0045400728,-0.005555795,-0.001965123,-0.031849343,-0.030794086,0.007521378,-0.0103563005,-0.01972265,-0.06663075,-0.06291946,-0.01058504,0.0484885,0.01167702,-0.010327916,0.0656383,0.021774262,0.012588038,-0.019035012,-0.01545234,-0.05190473,0.0054901456,-0.001017858,0.0037915693,-0.053926412,-0.02375191,-0.03642885,0.039513454,-0.012605841,0.0071300482,-0.030740365,-0.004961338,-0.055859588,-0.019751891,-0.0023523197,0.0069345008,0.0008066224,0.017386993,-0.023420837,0.030047806,-0.033406183,-0.039400205,-0.023938907,-0.03187806,-0.01553795,0.011109352,0.015865121,0.020464597,0.024370536,0.014801676,-0.0465313,-0.019196266,0.006728644,-0.026232652,0.0026793422,-0.047297254,-0.02453005,-0.030720346,0.03209326,0.0053294506,-0.0016596835,-0.08915088,-0.0057227775,-0.018532982,-0.00058829173,0.005355838,0.016101379,0.030155707,0.07134538,-0.06400611,-0.019341882,-0.045054976,-0.016791178,-0.012859251,0.03034105,0.022257224,-0.039108135,-0.017415317,0.06128742,-0.012120804,0.026160039,0.010535686,0.04848866,-0.0001206655,0.035607133,-0.0043966835,0.02866406,0.0103850225,0.039947134,0.007304378,0.029810125,-0.07167918,0.007436847,0.044667736,-0.01175691,-0.02837235,-0.07126029,-0.01819114,0.0062729465,0.023215018,-0.009476411,0.023053652,0.01890013,0.0073491633,0.067957036,-0.06890421,0.0047820