INSERT INTO public.meme_templates (name,description,image_url,text_box_count,example_texts,tags,popularity_score,embedding,created_at) VALUES
	 ('Finding-Neverland','This meme template consists of three sequential panels, creating a narrative progression that''s often used to convey emotional or dramatic moments.

In the first panel, we see a close-up of a young boy''s face. He appears to be looking up at someone off-screen, his expression a mix of curiosity and slight apprehension. The boy has light-colored hair and is wearing what looks like a formal suit jacket, suggesting a sophisticated or serious setting.

The second panel shows a man in a dark suit looking down, presumably at the boy from the first panel. His expression is somber and thoughtful, conveying a sense of gravity to the situation. The background in both these panels is blurred but appears to be outdoors, with green tones suggesting a natural setting.

The third and final panel is a wider shot, showing the man and boy sitting together on a park bench. The man has his arm around the boy in a comforting or protective gesture. They are surrounded by trees in what looks like a formal garden or park, with a row of trees creating a vanishing point perspective behind them. The overall tone of this panel is one of intimacy and emotional connection.

The progression of these images suggests a story of a serious conversation or moment of revelation between an adult and a child, moving from initial curiosity, through contemplation, to a moment of shared understanding or comfort. The formal attire and setting add to the sense of importance or gravity of the situation.

This template is often used in memes to represent moments of realization, the delivery of hard truths, or the formation of unexpected bonds. The stark emotional contrast between the panels and the clear visual storytelling make it a versatile format for various humorous or poignant meme concepts.','/memes/Finding-Neverland.jpg',2,'{}','{"Johnny Depp And Little Kid Crying","dad and son cry"}',0.0,'[0.031177891,-0.013622774,0.025951805,0.015402114,0.037510417,-0.059175912,-0.023876013,-0.009091635,0.0043733516,0.026030377,0.0026147126,0.012346336,0.010675911,0.010379527,-0.010088894,0.0072052404,0.0006394333,-0.021545377,-0.031259116,0.025673402,-0.016351132,0.024953581,-0.075669274,-0.028120544,-0.015107392,0.06859708,-0.0021511994,0.018245496,0.05889399,0.032034382,0.011503339,0.0058644637,-0.00098545,-0.04130297,-0.00876643,0.01267514,0.019599283,-0.060472567,0.012403232,-0.01209813,0.032865174,-0.008788225,0.03604382,-0.022738082,-0.032905273,-0.021230873,-0.008178989,-0.016029721,0.009905386,-0.00096535834,0.019073281,-0.035759248,0.043379534,0.010204839,-0.023932628,-0.031509023,-0.007906603,-0.0024695003,0.0140173305,0.038886614,0.020092214,0.014319953,0.0026637511,-0.041513957,-0.01197161,0.015777396,-0.037610132,-0.008908225,-0.016014718,-0.010303094,-0.01861403,0.028398074,-0.0018197478,0.02602642,-0.023438988,0.006079651,-0.032745913,-0.021978162,0.04790091,8.180408e-05,0.030507276,0.056394346,-0.008740796,-0.025566053,-0.022150835,-0.04841378,0.020142093,0.027865626,0.0359053,-0.02972382,-0.0051534865,0.04288387,0.0017705662,0.009541831,-0.017929127,0.045035135,-0.02522919,0.04667847,-0.015270059,0.029809397,-0.024303863,0.041046157,-0.013812409,0.019016756,-0.05190553,0.006268045,0.036370896,-0.006591208,-0.026001891,-0.02970928,0.0220322,-0.017363176,-0.010232388,-0.013811914,-0.02391535,0.04804425,0.015503779,0.027445301,-0.047977835,0.0021255766,-0.03529312,-0.017952431,-0.038425617,-0.006402075,-0.00613539,-0.016279547,0.003110859,0.030579224,-0.06300