INSERT INTO public.meme_templates (name,description,image_url,text_box_count,example_texts,tags,popularity_score,embedding,created_at) VALUES
	 ('Matrix-Morpheus','This meme template features a close-up shot of a man''s face, capturing a moment of intense scrutiny or realization. The subject is a bald African American man wearing reflective sunglasses that dominate his facial features. These sunglasses are not just accessories but seem to be a defining characteristic, reflecting what appears to be other people or scenes in their lenses.

The man''s expression is stern and contemplative, with his mouth slightly open as if he''s about to speak or has just had an epiphany. His skin tone contrasts sharply with the dark sunglasses and the muted, greenish background, creating a striking visual composition.

The overall atmosphere of the image is tense and serious, evoking a sense of a pivotal moment in a narrative. The lighting is subdued, contributing to a moody, almost noir-like aesthetic that''s often associated with dystopian or science fiction themes.

This particular frame is recognizable as being from the "Matrix" film series, which has become deeply ingrained in popular culture. The character''s iconic look – bald head, stern expression, and reflective sunglasses – has made this image a popular template for memes expressing moments of sudden realization, skepticism, or seeing through deception.

The composition draws the viewer''s focus directly to the man''s face, particularly his eyes (or rather, the sunglasses covering them), making it an effective image for conveying reactions or profound moments of understanding. This template is often used to comment on societal revelations, conspiracy theories, or moments when someone "sees the truth" behind a situation.','/memes/Matrix-Morpheus.jpg',2,'{}','{"what if I told you",morpheous}',0.0,'[0.031225402,-0.029035386,0.01774449,0.025472974,-0.0062283925,-0.040519346,-0.04315243,-0.041290767,-0.038511224,0.047371075,-0.0051526628,-0.01646539,0.037533168,0.015222324,-0.0034240235,-0.010742658,0.010967766,-0.010411029,-0.006539164,0.013966567,-0.0011438894,0.017049527,-0.07153969,-0.0552297,-0.0038936196,0.03972362,-0.039604113,0.021904262,0.040130395,0.06057029,0.020658737,0.0014565808,0.010583666,-0.046802774,-0.0070751663,-0.018366845,0.026843565,-0.05304851,-0.008613513,-0.012869418,0.026774304,-0.021406561,0.014013518,0.002444582,-0.049485866,-0.042879965,-0.018173605,0.0060928133,0.02701351,0.0064101336,0.00015479566,-0.0045324326,0.032267988,0.022455001,-0.021375386,-0.034333915,-0.0068120575,0.020143978,-0.0007884281,0.006591142,0.022235775,0.0034903756,-0.0055118864,-0.0150794,-0.020972956,0.028294718,-0.026142411,-0.0054257233,-0.010337651,-0.010197433,0.007733087,-0.028746925,0.03376676,-0.0011515865,-0.022076083,-0.0038617477,-0.028759113,-0.028462827,0.05424408,-0.019386144,0.0011860911,0.046208695,-0.014579777,-0.02409624,-0.0153581,-0.0070449705,-0.0022410906,0.040852137,0.009272695,-0.042202104,0.012861962,0.03737253,-0.00025990387,0.015954608,0.030055944,0.03423386,0.012456858,0.04676648,0.002674776,0.029023966,-0.035876285,0.067903854,-0.04092754,0.046516854,0.0014771898,0.009643549,0.012183274,0.006882257,-0.026446864,-0.03455864,0.027821826,-0.027533509,0.008515734,0.011802282,-0.058100075,0.046641044,0.0026807308,0.054449316,-0.021394392,-0.014223248,-0.06078541,-0.021278577,-0.015068753,-0.019