INSERT INTO public.meme_templates (name,description,image_url,text_box_count,example_texts,tags,popularity_score,embedding,created_at) VALUES
	 ('Monkey-Puppet','This meme template features two side-by-side images of the same cartoon monkey head, reminiscent of a character from a children''s TV show or animated series. The monkey has a distinctive appearance with a large, round head covered in reddish-orange fur that dominates most of the frame. Its face is a lighter orange or tan color.

The monkey''s most striking feature is its exaggerated, bulbous eyes. In the left image, the eyes are looking straight ahead, while in the right image, they are glancing to the side, creating a sense of shifty or suspicious movement. This eye movement is the key element of the meme, often used to convey a sense of doubt, skepticism, or nervous energy.

The monkey''s expression is somewhat ambiguous, with a slightly open mouth that could be interpreted as surprise, confusion, or mild distress. The simple, stylized features give the character an almost puppet-like quality.

The background is blurry but suggests an outdoor setting with hints of blue sky and possibly green foliage. A small portion of what appears to be a light green shirt or body is visible at the bottom of the frame.

The image quality is somewhat low, with a slightly grainy or pixelated appearance, which is common in memes that have been widely shared and reposted. This low-fidelity aesthetic adds to the comedic effect and recognizability of the meme.

This template is typically used to express reaction to situations where someone is caught off guard, trying to avoid something, or feeling uncomfortable. The side-by-side nature of the images, with the subtle eye movement, allows for a before-and-after or cause-and-effect setup in meme usage.','/memes/Monkey-Puppet.jpg',2,'{}','{"monkey looking away","monkey puppet avoids eye contact","hiding in plain sight","awkward look monkey","monkey looking away meme","thanos wipeing out half of earth"}',0.0,'[0.030799232,-0.035334762,0.014525721,0.00749041,0.033316974,-0.040036406,-0.04095241,-0.022782076,-0.01773771,0.053320967,0.0019276191,-0.017552827,0.020398898,0.02941595,-0.028213393,0.006459817,-0.0046061906,-0.034876164,-0.010067,-0.0014190142,0.0064861225,0.015746647,-0.057187974,-0.024745721,0.0047965464,0.054797433,-0.0008203884,-0.0040536597,0.075187266,0.04238191,0.007646537,0.0005727033,0.008030133,-0.051439483,0.016419468,-0.003492064,0.051239207,-0.037877653,-0.012241743,-0.046583705,0.044702403,0.002010122,0.025630856,-0.036697958,-0.032840304,-0.007584149,-0.019424306,0.025685823,0.03375606,-0.008048261,0.019176077,-0.02901638,-0.0046276967,0.02311614,-0.043243773,-0.056139395,0.002465045,-0.025032388,0.0055673975,0.029345468,0.04734215,0.03754916,-0.009293051,-0.071970694,-0.033385802,-0.011207752,-0.029516798,-0.02353717,-0.03562348,0.000360313,0.01109619,0.041361354,0.000977774,-0.02679508,-0.049180645,-0.035025995,-0.021279512,-0.019670445,-0.0019364023,0.0013096434,-0.0074946336,0.03622861,-0.00632289,-0.041086495,0.0029295352,0.0019976504,0.021875782,-0.0022846377,0.015164956,-0.04632241,-0.022970514,0.051177066,0.016425146,0.023108164,0.028541714,0.026656443,-0.008920611,0.027674492,-0.026662707,0.005772411,0.004967907,0.031999096,-0.0075714183,0.04613083,-0.01590512,-0.015479068,0.0053012986,0.012848548,-0.048717532,-0.04218531,0.0005400216,-0.029986499,0.004414532,0.012435653,-0.020168649,-0.011208453,-0.03218574,0.050322264,-0.053818822,-0.023912514