INSERT INTO public.meme_templates (name,description,image_url,text_box_count,example_texts,tags,popularity_score,embedding,created_at) VALUES
	 ('X-All-The-Y','This meme template features a simple yet expressive cartoon character known as the "All the Things" or "X All the Y" rage comic figure. The character is drawn in a basic stick-figure style with a distinctive large, circular head and a rectangular body.

The figure''s face dominates the image, with exaggerated features including huge, round eyes and an enormous, gaping mouth filled with visible teeth, giving an impression of intense excitement or enthusiasm. The character''s arms are outstretched, with one arm holding what appears to be a broom or stick, adding to the sense of energetic action.

The body of the figure is colored in a vibrant hot pink, contrasting sharply with the plain white of the head and arms. This color choice makes the character stand out boldly against the background.

Behind the figure is a bright yellow starburst or explosion shape, which amplifies the feeling of sudden, intense emotion or action. This yellow burst fills most of the background, creating a striking visual effect that draws attention to the character''s exuberant pose.

The simplicity of the drawing style, combined with the extreme expression and dynamic pose, makes this image highly versatile for expressing overwhelming enthusiasm, excitement, or the desire to do something to an excessive degree. It''s often used in memes to humorously represent going "all out" or embracing a concept or action fully and perhaps irrationally.

This meme template has become iconic in internet culture, recognized for its ability to convey a sense of over-the-top commitment or excitement about virtually any topic or activity, making it a popular choice for a wide range of humorous contexts.','/memes/X-All-The-Y.jpg',2,'{}','{"all the things","all of the things","what do we want"}',0.0,'[9.814394e-07,-0.0010999244,0.02369066,-0.0034789497,0.021570034,-0.051021405,0.039472394,0.009594585,0.02067058,0.0636673,0.002401889,0.006377909,0.035910863,-0.031894278,-0.00866487,0.010852129,-0.014420271,-0.030196065,-0.02817943,0.047881965,-0.0043488876,-0.03095087,-0.051296987,-0.04420075,0.01071001,0.061319567,-0.018926376,0.022311457,0.051403753,0.016291672,-0.022402547,-0.009909601,-0.008963536,-0.05224648,-0.01969976,-0.038754147,0.005999874,-0.050807018,-0.005012828,-0.036746547,0.02481316,-0.03219076,0.0280132,0.0014948047,-4.8935843e-05,-0.016840966,-0.016973598,-0.010913752,0.04450364,-0.03243744,0.022118255,-0.016068906,0.017480833,0.034117293,-0.02480561,-0.01288348,-0.013484603,-0.0063932594,0.027740069,0.0130338175,0.03227476,0.0049427627,-0.014459109,-0.060864404,-0.034910135,-0.013925127,-0.019247837,-0.027430065,-0.011031508,0.015005596,0.0034067403,0.02268181,0.0010539102,-0.059099216,-0.07431399,0.018924158,-0.03605151,-0.022853065,0.014179686,0.015719073,0.025259944,0.037459776,-0.025308406,0.0017638378,-0.016155455,-0.002201184,-0.0044523934,0.026179371,0.013712158,-0.042820547,-0.0016066681,0.034249905,0.011318813,0.028589917,0.048137374,0.015392334,-0.006041636,0.032319475,-0.022958156,-0.009566655,-0.008129828,0.041354574,-0.037465397,0.02166816,-0.041070193,0.013095673,0.025863105,0.025305707,-0.0157219,-0.060838245,0.02531504,-0.015968671,0.039156526,-0.011995347,-0.016565036,0.03477999,0.008659628,0.050900456,-0.042902384,-0.023436127,-0.011183983,-0.0051471926,-0.02232592,0.0020033019,-0.012074116,-0.017234195,-0.009465303,0.018308857,-0.01577136,0.031544693,-0.008529798,-0.009425191,0.01619156