INSERT INTO public.meme_templates (name,description,image_url,text_box_count,example_texts,tags,popularity_score,embedding,created_at) VALUES
	 ('Who-Killed-Hannibal','This meme template consists of two panels from what appears to be a comedy sketch or TV show, likely from the Adult Swim network as indicated by the watermark.

In the top panel, we see a talk show set with a distinctive red geometric backdrop. A man in a light gray suit, white shirt, and patterned tie is standing and pointing a gun towards a person slumped on a couch. The person on the couch is wearing a blue shirt and dark pants, and appears to be unconscious or possibly dead. There''s a small table with a globe on it to the right, and the floor is covered with a blue carpet.

The bottom panel shows the same scene moments later. The man in the suit is now facing the camera with a perplexed or slightly concerned expression. His arm is lowered, no longer holding the gun visibly. The person on the couch remains in the same position, and a small amount of smoke can be seen rising from that area, suggesting a recent gunshot.

The juxtaposition of these two images creates a sense of sudden realization or questioning after an impulsive action. The formal talk show setting contrasted with the violent act creates a surreal and darkly comedic atmosphere.

This template is often used in memes to represent situations where someone acts rashly and then immediately questions or regrets their decision, or to illustrate cause-and-effect scenarios with an ironic or unexpected twist.

The image quality, set design, and Adult Swim branding suggest this is from a professional comedy production, likely parodying or subverting typical talk show formats with absurdist or shocking humor.','/memes/Who-Killed-Hannibal.jpg',2,'{}','{"Eric Andre shooting Hannibal Buress","why would they do this","eric andre meme","why would do this"}',0.0,'[0.012503952,-0.009530594,0.009009283,0.026222173,0.01046641,-0.0707343,-0.0689186,0.016900346,-0.007925385,0.039220072,0.0058011753,0.0032752308,0.037807856,0.0014693592,-0.018484473,0.019285992,-0.01033242,0.011204258,-0.033476155,0.044014066,0.009892523,-0.021265224,-0.07836156,-0.018269997,-0.015653087,0.03305843,-0.022057727,0.0128617305,0.04215993,-0.0025421549,0.014570949,-0.030499522,-0.009289321,-0.05628506,0.010796372,0.0069050826,0.036863334,-0.04201077,0.0010645695,-0.021242442,0.012274866,0.0010028817,0.046466257,-0.014741865,-0.018943077,-0.039829828,-0.0061985953,0.0037276086,-0.018291945,0.020263257,0.041234236,-0.015264761,0.023623504,0.01024548,-0.025148895,-0.049812768,-0.030432537,-0.016055562,0.018838324,-0.0103651695,0.018711768,-0.013857757,-0.018682238,-0.051616278,-0.013997659,0.023954578,0.0050961846,-0.0054675313,-0.027740072,0.011317065,0.022243928,0.023774665,-0.019584911,0.03370538,-0.02009101,0.012166793,-0.03720336,-0.02885587,0.05639994,-0.013386689,0.029926395,0.041289225,0.020558782,-0.0426755,-0.02159632,-0.016606873,0.024512282,0.02305697,0.04484004,-0.02083933,0.0030165503,0.060106937,-0.018154703,-0.009020888,0.011163542,0.036474343,0.013774361,0.017729342,0.0065052453,-0.012508627,-0.017324619,0.032574315,-0.051487383,0.014041942,-0.044810362,0.029878022,0.04734507,0.005812405,-0.03572291,-0.034071375,0.035350837,-0.011231211,0.0060652653,0.024999527,-0.028535811,0.037188236,-0.00719542,0.025305964,-0.059882987,0.010042599,-0.0385941,-0.0040227855,-0.009029743,-0.0072315917,0.007965038,-0.028353548,0.043701895,0.03926801,-0.042324465,0.031750895,0.014176289,-0.029941663,-0.00650637