INSERT INTO public.meme_templates (name,description,image_url,text_box_count,example_texts,tags,popularity_score,embedding,created_at) VALUES
	 ('Spongebob-Ight-Imma-Head-Out','This meme template features a scene from the popular animated TV show SpongeBob SquarePants. The image captures SpongeBob sitting in his iconic pineapple house, but with a distinctly unenthusiastic and weary expression.

The background is instantly recognizable as SpongeBob''s living room, with its characteristic blue bamboo-patterned wallpaper. To the left, we see part of his wooden front door with its signature porthole window. On the right wall hangs a small framed picture of Gary the snail.

SpongeBob himself is seated on what appears to be a red armchair, but he''s actually perched atop a red and white striped lifesaver or swim ring. This creates a comical juxtaposition between the indoor setting and the beach-related object.

The character''s posture and expression are the focal points of the meme. SpongeBob looks tired and defeated, with half-lidded eyes and a slight frown. His usually energetic demeanor is replaced by an air of resignation or exhaustion. He''s slumped forward, one arm resting limply on the swim ring, conveying a sense of giving up or being completely done with a situation.

This image is often used in memes to express feelings of fatigue, frustration, or the desire to leave a tiresome situation. The contrast between SpongeBob''s typically cheerful character and this dejected pose makes the image particularly effective for humorous or relatable content.

The text at the bottom, "IGHT IMMA HEAD OUT," is commonly associated with this meme, though it''s worth noting that the original template wouldn''t include this text – it''s an addition that became popular with the meme''s usage.','/memes/Spongebob-Ight-Imma-Head-Out.jpg',2,'{}','{"Ight Imma Head Out","aight imma head out","spongebob aight","alright I''m out","spongebob getting out of chair"}',0.0,'[0.029066265,-0.027766805,0.0052060904,0.0063476427,0.032659695,-0.021461712,0.0056849835,-0.0031411997,0.031950846,0.006194836,0.024933444,0.019222261,0.010470371,0.0100540845,-0.001083409,-0.03328809,-0.0014474286,-0.00273984,-0.06594446,0.022582337,0.009499363,0.0023163157,-0.01853578,-0.010435522,-0.0075766565,0.03724416,0.023201942,0.02645539,0.040389832,0.018442262,0.03396509,-0.008241711,-0.009743458,-0.030647729,0.02117271,-0.020636164,0.028275229,-0.042566877,-0.0029703819,-0.038993914,0.0011503184,-0.021738077,0.004184499,4.74964e-05,0.007030711,-0.01729083,-0.03399927,0.0063040867,0.05375775,0.012476661,0.005650825,-0.0028042065,0.010319501,0.05233554,-0.011844076,-0.045414586,-0.029706677,0.039055225,0.02640096,0.013253545,0.032643862,-0.017027738,-0.049530268,-0.061030682,-0.03785578,-0.0007251461,0.002085083,-0.02439605,-0.004290785,-0.023131782,0.0029656736,0.021316113,0.02526485,-0.026765749,-0.03204609,-0.003869265,-0.032731492,0.025782047,0.012406203,0.043562323,0.045806747,0.050315455,0.039138805,-0.048176806,-0.01983153,-0.039595395,0.026985014,0.04089279,0.01499594,-0.056649752,-0.03438997,0.078623086,-0.012113154,0.020092761,0.009462792,0.030836318,0.00924824,0.05774511,0.023218267,-0.019358305,0.002143801,0.06213381,-0.025287306,0.021112554,-0.023269193,0.023422528,0.03720088,0.02378696,-0.06765272,-0.015984248,0.023574349,-0.0053117964,0.027355717,-0.00037312479,0.0012003494,0.035611045,-0.04826026,0.058890093,-0.040978547,-0.008187187,-0.026177175,0.008467842,0.0019302578,-0.021844637,0.007549608,-0.005989587,0.010323606,0.031879634,-0.035451952,0