INSERT INTO public.meme_templates (name,description,image_url,text_box_count,example_texts,tags,popularity_score,embedding,created_at) VALUES
	 ('Futurama-Fry','This meme template features a close-up of an animated character from the popular TV show "Futurama." The character, a young man with spiky orange hair, is shown from the shoulders up against a blue-gray background that appears to be the interior of a spaceship or futuristic building.

The character''s expression is one of skepticism or suspicion, with his eyes narrowed and his mouth drawn in a slight frown. His eyebrows are furrowed, adding to the look of doubt or confusion. This expression has made the image particularly useful for memes expressing skepticism, disbelief, or a moment of trying to process information.

The character is wearing a red jacket over a white shirt, which is consistent with his typical outfit in the show. His distinctive orange hair is styled in vertical spikes, a trademark of his appearance that makes him instantly recognizable to fans of the series.

The art style is characteristic of "Futurama," with bold lines, flat colors, and a slightly exaggerated cartoon aesthetic. The image is cropped to focus solely on the character''s face and upper body, emphasizing his reaction and making it ideal for meme usage where the expression is the key element.

This particular frame has become iconic in meme culture, often used to convey a moment of doubt, confusion, or when someone is trying to determine if they''re being deceived or if something doesn''t quite add up. The simplicity of the image and the clear, relatable expression make it versatile for a wide range of humorous or skeptical contexts in online discussions and social media posts.','/memes/Futurama-Fry.jpg',2,'{}','{"Not sure if X or Y","Skeptical Fry","blue futurama fry","not sure if...","confused fry","not sure if - futurama fry",suspicious}',0.0,'[0.065949075,-0.04219796,0.024849351,0.015837578,0.031439465,-0.05870477,0.016025312,-0.008065926,-0.012366847,0.059078813,0.0064127804,-0.03367717,0.053908207,0.013624102,-0.036196176,-0.0134122,0.0143039925,-0.00758793,-0.015837783,0.027153317,-0.016658012,0.019360434,-0.06381039,-0.016671369,-0.01856911,0.031264864,-0.006256486,-0.024791187,0.04981706,0.020374686,0.006123785,-0.020956576,-0.04033477,-0.034896374,-0.0083658565,0.0028879822,0.03227488,-0.02283172,-0.027561575,-0.06366743,0.021638367,-0.013711948,0.002989092,-0.017620074,-0.031703766,-0.025288414,-0.017076503,-0.019275643,0.024271144,0.014272591,0.0014112018,-0.001887924,0.009566528,0.02626146,-0.018042123,-0.048555203,0.009506529,0.022288373,-0.007475555,0.03972802,0.029831238,0.03589605,-0.024661819,-0.039291706,-0.032157443,0.021461802,-0.028251661,-0.0014477053,-0.022835724,0.021283755,0.011768691,0.034547236,0.004933935,0.0029307667,-0.06434441,0.0012562061,-0.023805324,-0.007948458,0.039835114,0.000226323,0.040319074,0.048993543,-0.031845383,-0.036377683,0.004912298,-0.0074806055,0.024005963,0.04272187,0.018478263,-0.02874263,-0.020525804,0.052966423,-0.0073336326,0.008400349,0.012806659,0.03737757,-0.02315849,0.07510883,0.0027426358,-0.007869932,-0.019847041,0.06185407,-0.028572492,0.018797616,-0.0080244765,0.0039145933,0.018866828,0.010738098,-0.021415837,-0.019062709,0.006446524,-0.018715922,0.00067341735,0.007911679,-0.046514004,0.02053